import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { getProducts, getCategories } from '../services/api';
import ProductCard from '../components/ProductCard';
import './Products.css';

export default function Products() {
    const [products, setProducts] = useState([]);
    const [categories, setCategories] = useState(['All']);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [category, setCategory] = useState('All');
    const [sort, setSort] = useState('');
    const [searchInput, setSearchInput] = useState('');

    useEffect(() => {
        const t = setTimeout(() => setSearch(searchInput), 350);
        return () => clearTimeout(t);
    }, [searchInput]);

    useEffect(() => {
        getCategories().then(r => setCategories(r.data.categories)).catch(() => {});
    }, []);

    const fetchProducts = useCallback(async() => {
        setLoading(true);
        try {
            const params = {};
            if (category !== 'All') params.category = category;
            if (search) params.search = search;
            if (sort) params.sort = sort;
            const { data } = await getProducts(params);
            setProducts(data.products);
        } catch { setProducts([]); } finally { setLoading(false); }
    }, [category, search, sort]);

    useEffect(() => { fetchProducts(); }, [fetchProducts]);

    return ( <
        div className = "products-page page-enter" >
        <
        div className = "products-header" >
        <
        div className = "container" >
        <
        motion.div initial = {
            { opacity: 0, y: 20 } }
        animate = {
            { opacity: 1, y: 0 } }
        transition = {
            { duration: 0.5 } } >
        <
        h1 className = "products-title" > The Collection < /h1> <
        p className = "products-subtitle" > { products.length }
        items available < /p> <
        /motion.div> <
        /div> <
        /div>

        <
        div className = "container products-layout" >
        <
        motion.aside className = "filters-sidebar"
        initial = {
            { opacity: 0, x: -20 } }
        animate = {
            { opacity: 1, x: 0 } }
        transition = {
            { duration: 0.5, delay: 0.1 } } >
        <
        div className = "filter-section" >
        <
        h3 className = "filter-label" > Search < /h3> <
        div className = "search-wrap" >
        <
        svg className = "search-icon"
        width = "16"
        height = "16"
        viewBox = "0 0 24 24"
        fill = "none"
        stroke = "currentColor"
        strokeWidth = "2" >
        <
        circle cx = "11"
        cy = "11"
        r = "8" / >
        <
        path d = "m21 21-4.35-4.35" / >
        <
        /svg> <
        input className = "form-input search-input"
        type = "text"
        placeholder = "Search products..."
        value = { searchInput }
        onChange = { e => setSearchInput(e.target.value) }
        /> {
            searchInput && ( <
                button className = "search-clear"
                onClick = {
                    () => setSearchInput('') } > × < /button>
            )
        } <
        /div> <
        /div>

        <
        div className = "filter-section" >
        <
        h3 className = "filter-label" > Category < /h3> <
        div className = "category-list" > {
            categories.map(cat => ( <
                button key = { cat }
                className = { `cat-btn ${category === cat ? 'active' : ''}` }
                onClick = {
                    () => setCategory(cat) } >
                { cat } < /button>
            ))
        } <
        /div> <
        /div>

        <
        div className = "filter-section" >
        <
        h3 className = "filter-label" > Sort By < /h3> <
        select className = "form-input sort-select"
        value = { sort }
        onChange = { e => setSort(e.target.value) } >
        <
        option value = "" > Default < /option> <
        option value = "price-asc" > Price: Low to High < /option> <
        option value = "price-desc" > Price: High to Low < /option> <
        option value = "rating" > Top Rated < /option> <
        /select> <
        /div>

        {
            (category !== 'All' || search || sort) && ( <
                button className = "btn btn-outline clear-filters"
                onClick = {
                    () => {
                        setCategory('All');
                        setSearchInput('');
                        setSort('');
                    }
                } >
                Clear Filters < /button>
            )
        } <
        /motion.aside>

        <
        main className = "products-main" >
        <
        AnimatePresence mode = "wait" > {
            loading ? ( <
                motion.div key = "loading"
                className = "loading-grid"
                initial = {
                    { opacity: 0 } }
                animate = {
                    { opacity: 1 } }
                exit = {
                    { opacity: 0 } } >
                {
                    Array.from({ length: 8 }).map((_, i) => ( <
                        div key = { i }
                        className = "skeleton-card" >
                        <
                        div className = "skeleton-img" / >
                        <
                        div className = "skeleton-body" >
                        <
                        div className = "skeleton-line" / >
                        <
                        div className = "skeleton-line short" / >
                        <
                        div className = "skeleton-line shorter" / >
                        <
                        /div> <
                        /div>
                    ))
                } <
                /motion.div>
            ) : products.length === 0 ? ( <
                motion.div key = "empty"
                className = "empty-state"
                initial = {
                    { opacity: 0, y: 20 } }
                animate = {
                    { opacity: 1, y: 0 } } >
                <
                div className = "empty-icon" > 🔍 < /div> <
                h3 > No products found < /h3> <
                p > Try adjusting your filters or search terms. < /p> <
                /motion.div>
            ) : ( <
                motion.div key = "grid"
                className = "products-grid" > {
                    products.map((p, i) => ( <
                        ProductCard key = { p.id }
                        product = { p }
                        index = { i }
                        />
                    ))
                } <
                /motion.div>
            )
        } <
        /AnimatePresence> <
        /main> <
        /div> <
        /div>
    );
}
